import { eq as eq2, and, desc, sql } from "drizzle-orm";
var MAX_AVATAR_SIZE = 100 * 1024;
var ALLOWED_AVATAR_MIME_MAP = {
  "image/jpeg": "jpg",
  "image/jpg": "jpg",
  "image/png": "png",
  "image/x-icon": "ico",
  "image/vnd.microsoft.icon": "ico",
  "image/ico": "ico",
  "image/svg+xml": "svg",
  "image/webp": "webp"
};
var getRequestUserRole = async (c3) => {
  const authorization = c3.req.header("authorization") || "";
  if (!authorization.startsWith("Bearer ")) {
    return "public";
  }
  const token = authorization.slice(7).trim();
  if (!token || token.length < 32) {
    return "public";
  }
  try {
    const session = db.select({
      id: sessions.id,
      uid: sessions.uid,
      role: sessions.role,
      expires_at: sessions.expires_at
    }).from(sessions).where(and(eq2(sessions.token, token), eq2(sessions.status, "active"))).get();
    if (!session) {
      return "public";
    }
    if (session.expires_at.getTime() <= Date.now()) {
      db.update(sessions).set({ status: "expired" }).where(eq2(sessions.id, session.id)).run();
      return "public";
    }
    const user = db.select({
      id: users.id
    }).from(users).where(and(eq2(users.id, session.uid), eq2(users.status, "active"))).get();
    if (!user) {
      return "public";
    }
    return session.role;
  } catch {
    return "public";
  }
};
var register = async (c3) => {
  const regSetting = getSettingValue("reg_setting");
  if (!regSetting) {
    return c3.json({
      code: -1000,
      msg: "register.not.allowed",
      data: null
    });
  }
  if (!regSetting.allow_register) {
    return c3.json({
      code: -1000,
      msg: "register.not.allowed",
      data: null
    });
  }
  const userCountResult = db.select({ count: sql`count(*)` }).from(users).get();
  const host = getHostFromRequest(c3);
  const { edition, result } = getLicense(host);
  let maxUsers = 1;
  if (edition === "pro" && result === "success") {
    maxUsers = 5;
  } else if (edition === "team" && result === "success") {
    maxUsers = 20;
  }
  if ((userCountResult?.count ?? 0) >= maxUsers) {
    return c3.json({
      code: -1000,
      msg: "license.user_limit.reached",
      data: null
    });
  }
  let { username, email: email3, password, invite_code } = await c3.req.json();
  const requiredInviteCode = regSetting.invite_code?.trim();
  if (requiredInviteCode && invite_code?.trim() !== requiredInviteCode) {
    return c3.json({
      code: -1000,
      msg: "invalid.invite.code",
      data: null
    });
  }
  username = username?.trim().toLowerCase() || "";
  if (!vUsername(username)) {
    return c3.json({
      code: -1000,
      msg: "invalid.username",
      data: null
    });
  }
  password = password?.trim() || "";
  if (!vPassword(password)) {
    return c3.json({
      code: -1000,
      msg: "invalid.password",
      data: null
    });
  }
  email3 = email3?.trim().toLowerCase() || "";
  if (!vEmail(email3)) {
    return c3.json({
      code: -1000,
      msg: "invalid.email",
      data: null
    });
  }
  const existingUsername = db.select().from(users).where(eq2(users.username, username)).get();
  if (existingUsername) {
    return c3.json({
      code: -1000,
      msg: "username.already.exists",
      data: null
    });
  }
  const existingEmail = db.select().from(users).where(eq2(users.email, email3)).get();
  if (existingEmail) {
    return c3.json({
      code: -1000,
      msg: "email.already.exists",
      data: null
    });
  }
  let userAgent = c3.req.header("user-agent") || "unknown";
  if (userAgent.length > 256) {
    userAgent = userAgent.substring(0, 256);
  }
  const reg_ip = getClientIp(c3);
  const enPass = enPassword(username, password);
  const [user] = await db.insert(users).values({
    reg_ua: userAgent,
    username,
    email: email3,
    password: enPass,
    reg_ip,
    role: "user"
  }).returning({
    id: users.id,
    username: users.username,
    email: users.email,
    role: users.role
  });
  const token = `web-${randomString(28)}`;
  const expiresAt = new Date(Date.now() + 1000 * 60 * 60 * 24 * 30);
  db.insert(sessions).values({
    uid: user.id,
    role: user.role,
    token,
    ip: reg_ip,
    ua: userAgent,
    expires_at: expiresAt
  }).run();
  return c3.json({
    code: 200,
    msg: "register.success",
    data: {
      id: user.id,
      username: user.username,
      email: user.email,
      role: user.role,
      token
    }
  });
};
