var sortLinks = async (c3) => {
  const body = await c3.req.json();
  const uid = c3.get("uid");
  if (!Array.isArray(body) || body.length === 0) {
    return c3.json({
      code: -1000,
      msg: "link.ids.required",
      data: null
    });
  }
  if (body.length > 200) {
    return c3.json({
      code: -1000,
      msg: "link.ids.too_many",
      data: null
    });
  }
  const seenIds = new Set;
  const items = [];
  for (const item of body) {
    if (!item || typeof item !== "object") {
      return c3.json({
        code: -1000,
        msg: "link.ids.invalid",
        data: null
      });
    }
    const { id, sort_order } = item;
    if (!Number.isInteger(id) || id <= 0 || seenIds.has(id)) {
      return c3.json({
        code: -1000,
        msg: "link.ids.invalid",
        data: null
      });
    }
    if (!Number.isInteger(sort_order) || sort_order < 0 || sort_order > 99999) {
      return c3.json({
        code: -1000,
        msg: "link.sort_order.invalid",
        data: null
      });
    }
    seenIds.add(id);
    items.push({ id, sort_order });
  }
  const ids = items.map((item) => item.id);
  const rows = await db.query.links.findMany({
    where: inArray4(links.id, ids),
    columns: {
      id: true,
      uid: true
    }
  });
  if (rows.length !== ids.length) {
    return c3.json({
      code: -1000,
      msg: "link.ids.not_found",
      data: null
    });
  }
  const hasUnauthorizedLink = rows.some((row) => row.uid !== uid);
  if (hasUnauthorizedLink) {
    return c3.json({
      code: -1000,
      msg: "link.permission.denied",
      data: null
    });
  }
  const updatedAt = new Date;
  try {
    await db.transaction(async (tx) => {
      for (const item of items) {
        const [row] = await tx.update(links).set({
          sort_order: item.sort_order,
          updated_at: updatedAt
        }).where(and6(eq8(links.id, item.id), eq8(links.uid, uid))).returning({
          id: links.id
        });
        if (!row) {
          throw new Error("link.sort_order.update_failed");
        }
      }
    });
  } catch {
    return c3.json({
      code: -1000,
      msg: "link.sort_order.update_failed",
      data: null
    });
  }
  return c3.json({
    code: 200,
    msg: "success",
    data: {
      count: items.length,
      ids
    }
  });
};
